import Foundation

enum BankError: Error {
    case insufficientFunds
    case invalidAmount
    case accountClosed
}

struct BankAccount {
    var balance: Double
    var isClosed: Bool = false

    func withdraw(_ amount: Double) throws {
        guard !isClosed else { throw BankError.accountClosed }
        guard amount > 0 else { throw BankError.invalidAmount }
        guard amount <= balance else { throw BankError.insufficientFunds }
        balance -= amount
    }
}

var account = BankAccount(balance: 100)

// Try to withdraw more than balance
do {
    try account.withdraw(150)
    print("Withdrawal successful, new balance: \(account.balance)")
} catch BankError.insufficientFunds {
    print("Error: Not enough funds")
} catch BankError.invalidAmount {
    print("Error: Invalid amount")
} catch BankError.accountClosed {
    print("Error: Account is closed")
} catch {
    print("Unknown error")
}

