import Foundation

enum BankError: Error {
    case insufficientFunds
    case invalidAmount
}

let account = BankAccount(balance: 100)

do {
    try account.withdraw(150)
} catch BankError.insufficientFunds {
    print("Error: Not enough funds")
}
